INSERT INTO public.classes (id, label, niveau, "order") VALUES ('terminale', 'Terminale', 'Lycée', 7) ON CONFLICT (id) DO UPDATE SET label = EXCLUDED.label, niveau = EXCLUDED.niveau, "order" = EXCLUDED."order";
INSERT INTO public.chapters (id, title, description, "order", icon, color) VALUES ('nombres-entiers-decimaux', 'Nombres entiers et décimaux', 'Comprendre la valeur de chaque chiffre (unités, dizaines, centaines, dixièmes, centièmes, millièmes) ; décomposer un nombre : 12,345 = 12 + 3/10 + 4/100 + 5/1000 ; lire, écrire, comparer et encadrer ; passer d''une fraction décimale à l''écriture à virgule et inversement ; arrondir, estimer un ordre de grandeur et vérifier la cohérence d''un résultat.', 1, 'hash', 'blue') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, description = EXCLUDED.description, "order" = EXCLUDED."order", icon = EXCLUDED.icon, color = EXCLUDED.color;
INSERT INTO public.chapter_classes (chapter_id, class_id) VALUES ('nombres-entiers-decimaux', '6eme') ON CONFLICT DO NOTHING;
INSERT INTO public.chapters (id, title, description, "order", icon, color) VALUES ('fractions', 'Les Fractions', 'Voir la fraction comme partage et comme quotient ; placer une fraction sur une droite graduée ; simplifier par un diviseur commun ; comparer et encadrer ; passer d''une fraction décimale à l''écriture à virgule ; calculer une part k/n d''une quantité ; ajouter ou soustraire des fractions de même dénominateur ; comprendre le sens d''une fraction impropre (>1).', 2, 'divide', 'red') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, description = EXCLUDED.description, "order" = EXCLUDED."order", icon = EXCLUDED.icon, color = EXCLUDED.color;
INSERT INTO public.chapter_classes (chapter_id, class_id) VALUES ('fractions', '6eme') ON CONFLICT DO NOTHING;
INSERT INTO public.chapter_classes (chapter_id, class_id) VALUES ('fractions', '5eme') ON CONFLICT DO NOTHING;
INSERT INTO public.chapters (id, title, description, "order", icon, color) VALUES ('algebre', 'Algèbre', 'Utiliser une lettre pour représenter un nombre inconnu ; traduire une phrase en expression numérique/littérale ; appliquer les priorités (parenthèses, multiplications/divisions, additions/soustractions) ; remplacer une lettre par une valeur pour calculer ; résoudre des égalités simples de la forme ax + b = c ; repérer des régularités dans des suites ou des figures et commencer à généraliser.', 3, 'variable', 'teal') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, description = EXCLUDED.description, "order" = EXCLUDED."order", icon = EXCLUDED.icon, color = EXCLUDED.color;
INSERT INTO public.chapter_classes (chapter_id, class_id) VALUES ('algebre', '6eme') ON CONFLICT DO NOTHING;
INSERT INTO public.chapters (id, title, description, "order", icon, color) VALUES ('longueurs', 'Les Longueurs', 'Maîtriser les unités (mm, cm, dm, m, km) avec tableau de conversion ; estimer un ordre de grandeur ; mesurer et tracer avec règle/compas ; calculer des périmètres : rectangle 2(L + l), carré 4c, cercle 2πr ; résoudre des problèmes de trajets cumulés et d''échelles simples.', 4, 'ruler', 'cyan') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, description = EXCLUDED.description, "order" = EXCLUDED."order", icon = EXCLUDED.icon, color = EXCLUDED.color;
INSERT INTO public.chapter_classes (chapter_id, class_id) VALUES ('longueurs', '6eme') ON CONFLICT DO NOTHING;
INSERT INTO public.chapters (id, title, description, "order", icon, color) VALUES ('aires', 'Les Aires', 'Utiliser les unités d''aire (m², dm², cm²) et convertir ; connaître les formules : rectangle A = L × l, carré A = c², triangle A = (b × h)/2, disque A = πr² ; relier périmètre et aire ; estimer et comparer des surfaces ; résoudre des problèmes de pavage, carrelage ou peinture.', 5, 'square', 'green') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, description = EXCLUDED.description, "order" = EXCLUDED."order", icon = EXCLUDED.icon, color = EXCLUDED.color;
INSERT INTO public.chapter_classes (chapter_id, class_id) VALUES ('aires', '6eme') ON CONFLICT DO NOTHING;
INSERT INTO public.chapter_classes (chapter_id, class_id) VALUES ('aires', '5eme') ON CONFLICT DO NOTHING;
INSERT INTO public.chapter_classes (chapter_id, class_id) VALUES ('aires', '4eme') ON CONFLICT DO NOTHING;
INSERT INTO public.chapters (id, title, description, "order", icon, color) VALUES ('volumes', 'Les Volumes', 'Reconnaître cube et pavé droit ; utiliser V = L × l × h et V = c³ ; lier volumes (m³, dm³, cm³) et capacités (L, mL) avec 1 L = 1 dm³ = 1000 cm³ ; approcher le volume d''autres solides simples ; résoudre des problèmes de remplissage, contenance et empilement.', 6, 'cube', 'amber') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, description = EXCLUDED.description, "order" = EXCLUDED."order", icon = EXCLUDED.icon, color = EXCLUDED.color;
INSERT INTO public.chapter_classes (chapter_id, class_id) VALUES ('volumes', '6eme') ON CONFLICT DO NOTHING;
INSERT INTO public.chapters (id, title, description, "order", icon, color) VALUES ('temps-durees', 'Repérage dans le temps et durées', 'Lire une horloge analogique ou numérique ; convertir heures, minutes, secondes (base 60) ; calculer une durée ou retrouver une heure de début/fin ; utiliser le calendrier (mois, jours, années bissextiles) ; estimer un temps de parcours et relier durée, distance, vitesse simple.', 7, 'clock', 'pink') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, description = EXCLUDED.description, "order" = EXCLUDED."order", icon = EXCLUDED.icon, color = EXCLUDED.color;
INSERT INTO public.chapter_classes (chapter_id, class_id) VALUES ('temps-durees', '6eme') ON CONFLICT DO NOTHING;
INSERT INTO public.chapters (id, title, description, "order", icon, color) VALUES ('geometrie-plane', 'Configurations planes', 'Mobiliser le vocabulaire : points, segments, droites, demi-droites ; identifier parallèles et perpendiculaires ; mesurer et construire des angles avec le rapporteur ; connaître les propriétés des triangles (isocèle, rectangle) et des quadrilatères usuels ; cercle : rayon, diamètre, centre ; utiliser équerre et compas ; repérer des axes de symétrie simples.', 8, 'triangle', 'indigo') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, description = EXCLUDED.description, "order" = EXCLUDED."order", icon = EXCLUDED.icon, color = EXCLUDED.color;
INSERT INTO public.chapter_classes (chapter_id, class_id) VALUES ('geometrie-plane', '6eme') ON CONFLICT DO NOTHING;
INSERT INTO public.chapters (id, title, description, "order", icon, color) VALUES ('vision-espace', 'Vision dans l''espace', 'Identifier cubes, pavés, prismes, cylindres, pyramides ; compter faces, arêtes, sommets ; lire et produire des vues de face/côté/haut ; comprendre et utiliser des patrons simples ; relier le volume d''un solide à la surface de son patron.', 9, 'box', 'violet') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, description = EXCLUDED.description, "order" = EXCLUDED."order", icon = EXCLUDED.icon, color = EXCLUDED.color;
INSERT INTO public.chapter_classes (chapter_id, class_id) VALUES ('vision-espace', '6eme') ON CONFLICT DO NOTHING;
INSERT INTO public.chapters (id, title, description, "order", icon, color) VALUES ('gestion-donnees', 'Organisation et gestion de données', 'Lire et compléter des tableaux ; choisir et interpréter un diagramme en barres ou circulaire ; calculer moyenne et étendue ; introduire fréquence et pourcentage simple ; critiquer ou valider une représentation en fonction des données.', 10, 'chart', 'slate') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, description = EXCLUDED.description, "order" = EXCLUDED."order", icon = EXCLUDED.icon, color = EXCLUDED.color;
INSERT INTO public.chapter_classes (chapter_id, class_id) VALUES ('gestion-donnees', '6eme') ON CONFLICT DO NOTHING;
INSERT INTO public.chapters (id, title, description, "order", icon, color) VALUES ('probabilites', 'Les Probabilités', 'Découvrir le hasard par des jeux (dé, pièce, urne) ; énumérer les issues et les événements ; distinguer événement certain, impossible, équiprobable ; exprimer une probabilité simple en fraction ou pourcentage ; comprendre que la somme des probabilités des issues vaut 1.', 11, 'dice', 'rose') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, description = EXCLUDED.description, "order" = EXCLUDED."order", icon = EXCLUDED.icon, color = EXCLUDED.color;
INSERT INTO public.chapter_classes (chapter_id, class_id) VALUES ('probabilites', '6eme') ON CONFLICT DO NOTHING;
INSERT INTO public.chapters (id, title, description, "order", icon, color) VALUES ('proportionnalite', 'La Proportionnalité', 'Repérer un tableau proportionnel (coefficient constant, linéarité) ; utiliser le passage à l''unité et le produit en croix ; manipuler pourcentages et échelles ; traiter des vitesses constantes et lire un graphique y = kx ; vérifier ou invalider la proportionnalité d''une situation.', 12, 'percent', 'purple') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, description = EXCLUDED.description, "order" = EXCLUDED."order", icon = EXCLUDED.icon, color = EXCLUDED.color;
INSERT INTO public.chapter_classes (chapter_id, class_id) VALUES ('proportionnalite', '6eme') ON CONFLICT DO NOTHING;
INSERT INTO public.chapter_classes (chapter_id, class_id) VALUES ('proportionnalite', '5eme') ON CONFLICT DO NOTHING;
INSERT INTO public.chapters (id, title, description, "order", icon, color) VALUES ('pensee-informatique', 'Pensée informatique', 'Décomposer un problème en étapes ; décrire un algorithme en mots ou en pseudo-code ; utiliser des boucles pour répéter des actions ; introduire des instructions conditionnelles simples ; tester, repérer et corriger une erreur (débogage) ; appliquer ces idées à des tracés ou à des suites d''actions.', 13, 'code', 'orange') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, description = EXCLUDED.description, "order" = EXCLUDED."order", icon = EXCLUDED.icon, color = EXCLUDED.color;
INSERT INTO public.chapter_classes (chapter_id, class_id) VALUES ('pensee-informatique', '6eme') ON CONFLICT DO NOTHING;
INSERT INTO public.exercises (id, chapter_id, difficulty, question, answer, unit, solution, hints) VALUES ('dec-ex-1', 'nombres-entiers-decimaux', 'facile', 'Quel est le chiffre des centièmes dans 14,567 ?', '6', '', '14,567 = 14 + 5/10 + 6/100 + 7/1000. Le centième est le 2ᵉ chiffre après la virgule : 6.', '{"Le deuxième chiffre après la virgule."}') ON CONFLICT (id) DO UPDATE SET chapter_id = EXCLUDED.chapter_id, difficulty = EXCLUDED.difficulty, question = EXCLUDED.question, answer = EXCLUDED.answer, unit = EXCLUDED.unit, solution = EXCLUDED.solution, hints = EXCLUDED.hints;
INSERT INTO public.exercises (id, chapter_id, difficulty, question, answer, unit, solution, hints) VALUES ('dec-ex-2', 'nombres-entiers-decimaux', 'facile', 'Écris le nombre trois cent vingt-quatre virgule cinq en chiffres.', '324,5', '', 'Partie entière : 324. Partie décimale : 0,5. On assemble 324 et ,5 → 324,5.', '{"Pense à séparer la partie entière et décimale."}') ON CONFLICT (id) DO UPDATE SET chapter_id = EXCLUDED.chapter_id, difficulty = EXCLUDED.difficulty, question = EXCLUDED.question, answer = EXCLUDED.answer, unit = EXCLUDED.unit, solution = EXCLUDED.solution, hints = EXCLUDED.hints;
INSERT INTO public.exercises (id, chapter_id, difficulty, question, answer, unit, solution, hints) VALUES ('dec-ex-3', 'nombres-entiers-decimaux', 'facile', 'Range dans l''ordre croissant : 5,3 ; 5,03 ; 5,33', '5,03 ; 5,3 ; 5,33', '', 'Complète 5,3 en 5,30 pour comparer : 5,03 < 5,30 < 5,33 donc ordre croissant = 5,03 ; 5,3 ; 5,33.', '{"Compare chiffre par chiffre après la virgule."}') ON CONFLICT (id) DO UPDATE SET chapter_id = EXCLUDED.chapter_id, difficulty = EXCLUDED.difficulty, question = EXCLUDED.question, answer = EXCLUDED.answer, unit = EXCLUDED.unit, solution = EXCLUDED.solution, hints = EXCLUDED.hints;
INSERT INTO public.exercises (id, chapter_id, difficulty, question, answer, unit, solution, hints) VALUES ('dec-ex-4', 'nombres-entiers-decimaux', 'moyen', 'Calcule 23,5 + 14,8', '38,3', '', 'Aligne les virgules : 23,5
INSERT INTO public.exercises (id, chapter_id, difficulty, question, answer, unit, solution, hints) VALUES ('dec-ex-5', 'nombres-entiers-decimaux', 'moyen', 'Calcule 45,6 - 12,3', '33,3', '', 'Aligne les virgules : 45,6 - 12,3. Soustrais unités (45-12=33) et dixièmes (0,6-0,3=0,3) → 33,3.', '{"Soustrais les dixièmes et les unités séparément."}') ON CONFLICT (id) DO UPDATE SET chapter_id = EXCLUDED.chapter_id, difficulty = EXCLUDED.difficulty, question = EXCLUDED.question, answer = EXCLUDED.answer, unit = EXCLUDED.unit, solution = EXCLUDED.solution, hints = EXCLUDED.hints;
INSERT INTO public.exercises (id, chapter_id, difficulty, question, answer, unit, solution, hints) VALUES ('dec-ex-6', 'nombres-entiers-decimaux', 'moyen', 'Multiplie 3,5 par 10', '35', '', 'Multiplier par 10 décale la virgule d''un rang à droite : 3,5 → 35.', '{"Multiplier par 10 décale la virgule."}') ON CONFLICT (id) DO UPDATE SET chapter_id = EXCLUDED.chapter_id, difficulty = EXCLUDED.difficulty, question = EXCLUDED.question, answer = EXCLUDED.answer, unit = EXCLUDED.unit, solution = EXCLUDED.solution, hints = EXCLUDED.hints;
INSERT INTO public.exercises (id, chapter_id, difficulty, question, answer, unit, solution, hints) VALUES ('dec-ex-7', 'nombres-entiers-decimaux', 'moyen', 'Divise 48 par 10', '4,8', '', 'Diviser par 10 décale la virgule d''un rang à gauche : 48 → 4,8.', '{"Diviser par 10 décale la virgule."}') ON CONFLICT (id) DO UPDATE SET chapter_id = EXCLUDED.chapter_id, difficulty = EXCLUDED.difficulty, question = EXCLUDED.question, answer = EXCLUDED.answer, unit = EXCLUDED.unit, solution = EXCLUDED.solution, hints = EXCLUDED.hints;
INSERT INTO public.exercises (id, chapter_id, difficulty, question, answer, unit, solution, hints) VALUES ('dec-ex-8', 'nombres-entiers-decimaux', 'difficile', 'Arrondis 67,849 au dixième près.', '67,8', '', 'On arrondit au dixième : on regarde le centième (4). Comme 4 < 5, on abaisse et on garde 67,8.', '{"Regarde le chiffre des centièmes."}') ON CONFLICT (id) DO UPDATE SET chapter_id = EXCLUDED.chapter_id, difficulty = EXCLUDED.difficulty, question = EXCLUDED.question, answer = EXCLUDED.answer, unit = EXCLUDED.unit, solution = EXCLUDED.solution, hints = EXCLUDED.hints;
INSERT INTO public.exercises (id, chapter_id, difficulty, question, answer, unit, solution, hints) VALUES ('dec-ex-9', 'nombres-entiers-decimaux', 'difficile', 'Calcule 12,5 × 4', '50', '', 'Décompose 12,5 = 12 + 0,5. 12 × 4 = 48 et 0,5 × 4 = 2. Somme = 48 + 2 = 50.', '{"Décompose 12,5 en 12 + 0,5."}') ON CONFLICT (id) DO UPDATE SET chapter_id = EXCLUDED.chapter_id, difficulty = EXCLUDED.difficulty, question = EXCLUDED.question, answer = EXCLUDED.answer, unit = EXCLUDED.unit, solution = EXCLUDED.solution, hints = EXCLUDED.hints;
INSERT INTO public.exercises (id, chapter_id, difficulty, question, answer, unit, solution, hints) VALUES ('dec-ex-10', 'nombres-entiers-decimaux', 'difficile', 'Quelle est la partie décimale de 145,672 ?', '0,672', '', 'Sépare partie entière (145) et partie décimale (tout après la virgule). Ici la partie décimale est 0,672.', '{"C''est ce qui vient après la virgule."}') ON CONFLICT (id) DO UPDATE SET chapter_id = EXCLUDED.chapter_id, difficulty = EXCLUDED.difficulty, question = EXCLUDED.question, answer = EXCLUDED.answer, unit = EXCLUDED.unit, solution = EXCLUDED.solution, hints = EXCLUDED.hints;
INSERT INTO public.exercises (id, chapter_id, difficulty, question, answer, unit, solution, hints) VALUES ('frac-ex-1', 'fractions', 'facile', 'Quelle fraction représente 1 part sur 4 ?', '1/4', '', 'Une fraction s''écrit (parts prises)/(parts totales). Pour 1 part sur 4 : 1/4.', '{"Nombre de parts sur total de parts."}') ON CONFLICT (id) DO UPDATE SET chapter_id = EXCLUDED.chapter_id, difficulty = EXCLUDED.difficulty, question = EXCLUDED.question, answer = EXCLUDED.answer, unit = EXCLUDED.unit, solution = EXCLUDED.solution, hints = EXCLUDED.hints;
INSERT INTO public.exercises (id, chapter_id, difficulty, question, answer, unit, solution, hints) VALUES ('frac-ex-2', 'fractions', 'facile', 'Calcule la moitié de 18.', '9', '', 'La moitié c''est diviser par 2 : 18 ÷ 2 = 9.', '{"La moitié = diviser par 2."}') ON CONFLICT (id) DO UPDATE SET chapter_id = EXCLUDED.chapter_id, difficulty = EXCLUDED.difficulty, question = EXCLUDED.question, answer = EXCLUDED.answer, unit = EXCLUDED.unit, solution = EXCLUDED.solution, hints = EXCLUDED.hints;
INSERT INTO public.exercises (id, chapter_id, difficulty, question, answer, unit, solution, hints) VALUES ('frac-ex-3', 'fractions', 'facile', 'Quelle est la fraction de 3 parts sur 5 ?', '3/5', '', 'Numérateur = parts prises (3), dénominateur = total (5). Fraction = 3/5.', '{"Numérateur = parts prises, dénominateur = total."}') ON CONFLICT (id) DO UPDATE SET chapter_id = EXCLUDED.chapter_id, difficulty = EXCLUDED.difficulty, question = EXCLUDED.question, answer = EXCLUDED.answer, unit = EXCLUDED.unit, solution = EXCLUDED.solution, hints = EXCLUDED.hints;
INSERT INTO public.exercises (id, chapter_id, difficulty, question, answer, unit, solution, hints) VALUES ('frac-ex-4', 'fractions', 'moyen', 'Calcule les 2/3 de 12.', '8', '', '2/3 de 12 = 12 × 2/3. Méthode : divise d''abord par 3 → 4, puis multiplie par 2 → 8.', '{"Divise par le dénominateur, multiplie par le numérateur."}') ON CONFLICT (id) DO UPDATE SET chapter_id = EXCLUDED.chapter_id, difficulty = EXCLUDED.difficulty, question = EXCLUDED.question, answer = EXCLUDED.answer, unit = EXCLUDED.unit, solution = EXCLUDED.solution, hints = EXCLUDED.hints;
INSERT INTO public.exercises (id, chapter_id, difficulty, question, answer, unit, solution, hints) VALUES ('frac-ex-5', 'fractions', 'moyen', 'Calcule les 3/4 de 20 €.', '15', '€', '3/4 de 20 = 20 × 3/4. Divise par 4 → 5, puis multiplie par 3 → 15 €.', '{"Divise d''abord 20 par 4, puis multiplie par 3."}') ON CONFLICT (id) DO UPDATE SET chapter_id = EXCLUDED.chapter_id, difficulty = EXCLUDED.difficulty, question = EXCLUDED.question, answer = EXCLUDED.answer, unit = EXCLUDED.unit, solution = EXCLUDED.solution, hints = EXCLUDED.hints;
INSERT INTO public.exercises (id, chapter_id, difficulty, question, answer, unit, solution, hints) VALUES ('frac-ex-6', 'fractions', 'moyen', 'Simplifie la fraction 6/12.', '1/2', '', 'Simplifie par le plus grand diviseur commun 6 : 6/12 = (6÷6)/(12÷6) = 1/2.', '{"Trouve le diviseur commun (ici 6)."}') ON CONFLICT (id) DO UPDATE SET chapter_id = EXCLUDED.chapter_id, difficulty = EXCLUDED.difficulty, question = EXCLUDED.question, answer = EXCLUDED.answer, unit = EXCLUDED.unit, solution = EXCLUDED.solution, hints = EXCLUDED.hints;
INSERT INTO public.exercises (id, chapter_id, difficulty, question, answer, unit, solution, hints) VALUES ('frac-ex-7', 'fractions', 'moyen', 'Compare 1/2 et 1/3. Laquelle est la plus grande ?', '1/2', '', 'Compare les valeurs décimales : 1/2 = 0,5 ; 1/3 ≈ 0,33. 0,5 est plus grand, donc 1/2 > 1/3.', '{"Plus le dénominateur est grand, plus les parts sont petites."}') ON CONFLICT (id) DO UPDATE SET chapter_id = EXCLUDED.chapter_id, difficulty = EXCLUDED.difficulty, question = EXCLUDED.question, answer = EXCLUDED.answer, unit = EXCLUDED.unit, solution = EXCLUDED.solution, hints = EXCLUDED.hints;
INSERT INTO public.exercises (id, chapter_id, difficulty, question, answer, unit, solution, hints) VALUES ('frac-ex-8', 'fractions', 'difficile', 'Calcule 1/2 + 1/4.', '3/4', '', 'Mets au même dénominateur : 1/2 = 2/4. Addition : 2/4 + 1/4 = 3/4.', '{"Mets au même dénominateur."}') ON CONFLICT (id) DO UPDATE SET chapter_id = EXCLUDED.chapter_id, difficulty = EXCLUDED.difficulty, question = EXCLUDED.question, answer = EXCLUDED.answer, unit = EXCLUDED.unit, solution = EXCLUDED.solution, hints = EXCLUDED.hints;
INSERT INTO public.exercises (id, chapter_id, difficulty, question, answer, unit, solution, hints) VALUES ('frac-ex-9', 'fractions', 'difficile', 'Écris 7/4 sous forme de nombre mixte.', '1 et 3/4', '', 'Divise 7 par 4 : on fait 1 entier et il reste 3. Donc 7/4 = 1 + 3/4.', '{"Combien de fois 4 dans 7 ?"}') ON CONFLICT (id) DO UPDATE SET chapter_id = EXCLUDED.chapter_id, difficulty = EXCLUDED.difficulty, question = EXCLUDED.question, answer = EXCLUDED.answer, unit = EXCLUDED.unit, solution = EXCLUDED.solution, hints = EXCLUDED.hints;
INSERT INTO public.exercises (id, chapter_id, difficulty, question, answer, unit, solution, hints) VALUES ('frac-ex-10', 'fractions', 'difficile', 'Quelle fraction de 24 est égale à 18 ?', '3/4', '', 'Écris 18/24 puis simplifie par 6 : (18÷6)/(24÷6) = 3/4.', '{"Écris 18/24 et simplifie."}') ON CONFLICT (id) DO UPDATE SET chapter_id = EXCLUDED.chapter_id, difficulty = EXCLUDED.difficulty, question = EXCLUDED.question, answer = EXCLUDED.answer, unit = EXCLUDED.unit, solution = EXCLUDED.solution, hints = EXCLUDED.hints;
INSERT INTO public.exercises (id, chapter_id, difficulty, question, answer, unit, solution, hints) VALUES ('alg-ex-1', 'algebre', 'facile', 'Si x = 5, calcule x + 3.', '8', '', 'Remplace x par 5 : x + 3 = 5 + 3 = 8.', '{"Remplace x par sa valeur."}') ON CONFLICT (id) DO UPDATE SET chapter_id = EXCLUDED.chapter_id, difficulty = EXCLUDED.difficulty, question = EXCLUDED.question, answer = EXCLUDED.answer, unit = EXCLUDED.unit, solution = EXCLUDED.solution, hints = EXCLUDED.hints;
INSERT INTO public.exercises (id, chapter_id, difficulty, question, answer, unit, solution, hints) VALUES ('alg-ex-2', 'algebre', 'facile', 'Si a = 7, calcule 2 × a.', '14', '', 'Remplace a par 7 puis multiplie : 2 × 7 = 14.', '{"Multiplie 2 par la valeur de a."}') ON CONFLICT (id) DO UPDATE SET chapter_id = EXCLUDED.chapter_id, difficulty = EXCLUDED.difficulty, question = EXCLUDED.question, answer = EXCLUDED.answer, unit = EXCLUDED.unit, solution = EXCLUDED.solution, hints = EXCLUDED.hints;
INSERT INTO public.exercises (id, chapter_id, difficulty, question, answer, unit, solution, hints) VALUES ('alg-ex-3', 'algebre', 'facile', 'Complète : 5 + ... = 12', '7', '', 'On cherche le nombre qui manque : 5 + ? = 12 ⇒ ? = 12 - 5 = 7.', '{"Quelle valeur ajouter à 5 pour obtenir 12 ?"}') ON CONFLICT (id) DO UPDATE SET chapter_id = EXCLUDED.chapter_id, difficulty = EXCLUDED.difficulty, question = EXCLUDED.question, answer = EXCLUDED.answer, unit = EXCLUDED.unit, solution = EXCLUDED.solution, hints = EXCLUDED.hints;
INSERT INTO public.exercises (id, chapter_id, difficulty, question, answer, unit, solution, hints) VALUES ('alg-ex-4', 'algebre', 'moyen', 'Si n = 4, calcule 3 × n - 2.', '10', '', 'Priorité à la multiplication : 3 × 4 = 12, puis 12 - 2 = 10.', '{"Multiplie d''abord, puis soustrais."}') ON CONFLICT (id) DO UPDATE SET chapter_id = EXCLUDED.chapter_id, difficulty = EXCLUDED.difficulty, question = EXCLUDED.question, answer = EXCLUDED.answer, unit = EXCLUDED.unit, solution = EXCLUDED.solution, hints = EXCLUDED.hints;
INSERT INTO public.exercises (id, chapter_id, difficulty, question, answer, unit, solution, hints) VALUES ('alg-ex-5', 'algebre', 'moyen', 'Trouve x si x + 8 = 15.', '7', '', 'Isoler x : x + 8 = 15 ⇒ x = 15 - 8 = 7.', '{"Soustrais 8 des deux côtés."}') ON CONFLICT (id) DO UPDATE SET chapter_id = EXCLUDED.chapter_id, difficulty = EXCLUDED.difficulty, question = EXCLUDED.question, answer = EXCLUDED.answer, unit = EXCLUDED.unit, solution = EXCLUDED.solution, hints = EXCLUDED.hints;
INSERT INTO public.exercises (id, chapter_id, difficulty, question, answer, unit, solution, hints) VALUES ('alg-ex-6', 'algebre', 'moyen', 'Si y = 6, calcule y × 2 + 5.', '17', '', 'Calcule le produit puis ajoute : 6 × 2 = 12 ; 12 + 5 = 17.', '{"Effectue la multiplication en premier."}') ON CONFLICT (id) DO UPDATE SET chapter_id = EXCLUDED.chapter_id, difficulty = EXCLUDED.difficulty, question = EXCLUDED.question, answer = EXCLUDED.answer, unit = EXCLUDED.unit, solution = EXCLUDED.solution, hints = EXCLUDED.hints;
INSERT INTO public.exercises (id, chapter_id, difficulty, question, answer, unit, solution, hints) VALUES ('alg-ex-7', 'algebre', 'moyen', 'Trouve a si 2 × a = 18.', '9', '', 'Isoler a : 2 × a = 18 ⇒ a = 18 ÷ 2 = 9.', '{"Divise 18 par 2."}') ON CONFLICT (id) DO UPDATE SET chapter_id = EXCLUDED.chapter_id, difficulty = EXCLUDED.difficulty, question = EXCLUDED.question, answer = EXCLUDED.answer, unit = EXCLUDED.unit, solution = EXCLUDED.solution, hints = EXCLUDED.hints;
INSERT INTO public.exercises (id, chapter_id, difficulty, question, answer, unit, solution, hints) VALUES ('alg-ex-8', 'algebre', 'difficile', 'Si b = 3, calcule 4 × b + 2 × b.', '18', '', 'Calcule chaque terme : 4 × 3 = 12, 2 × 3 = 6, somme = 18.', '{"Calcule chaque terme séparément."}') ON CONFLICT (id) DO UPDATE SET chapter_id = EXCLUDED.chapter_id, difficulty = EXCLUDED.difficulty, question = EXCLUDED.question, answer = EXCLUDED.answer, unit = EXCLUDED.unit, solution = EXCLUDED.solution, hints = EXCLUDED.hints;
INSERT INTO public.exercises (id, chapter_id, difficulty, question, answer, unit, solution, hints) VALUES ('alg-ex-9', 'algebre', 'difficile', 'Trouve m si 3 × m - 5 = 10.', '5', '', 'Ajoute 5 aux deux côtés : 3m = 15. Puis divise par 3 : m = 15 ÷ 3 = 5.', '{"Ajoute 5 aux deux côtés d''abord."}') ON CONFLICT (id) DO UPDATE SET chapter_id = EXCLUDED.chapter_id, difficulty = EXCLUDED.difficulty, question = EXCLUDED.question, answer = EXCLUDED.answer, unit = EXCLUDED.unit, solution = EXCLUDED.solution, hints = EXCLUDED.hints;
INSERT INTO public.exercises (id, chapter_id, difficulty, question, answer, unit, solution, hints) VALUES ('alg-ex-10', 'algebre', 'difficile', 'Simplifie l''expression 2x + 3x.', '5x', '', 'On additionne les termes en x : 2x + 3x = (2 + 3)x = 5x.', '{"2 termes de x + 3 termes de x = ?"}') ON CONFLICT (id) DO UPDATE SET chapter_id = EXCLUDED.chapter_id, difficulty = EXCLUDED.difficulty, question = EXCLUDED.question, answer = EXCLUDED.answer, unit = EXCLUDED.unit, solution = EXCLUDED.solution, hints = EXCLUDED.hints;
INSERT INTO public.exercises (id, chapter_id, difficulty, question, answer, unit, solution, hints) VALUES ('long-ex-1', 'longueurs', 'facile', 'Convertis 3 m en cm.', '300', 'cm', '1 m = 100 cm, donc 3 m = 3 × 100 = 300 cm.', '{"Multiplie par 100."}') ON CONFLICT (id) DO UPDATE SET chapter_id = EXCLUDED.chapter_id, difficulty = EXCLUDED.difficulty, question = EXCLUDED.question, answer = EXCLUDED.answer, unit = EXCLUDED.unit, solution = EXCLUDED.solution, hints = EXCLUDED.hints;
INSERT INTO public.exercises (id, chapter_id, difficulty, question, answer, unit, solution, hints) VALUES ('long-ex-2', 'longueurs', 'facile', 'Convertis 2000 m en km.', '2', 'km', '1 km = 1000 m, donc 2000 m = 2000 ÷ 1000 = 2 km.', '{"Divise par 1000."}') ON CONFLICT (id) DO UPDATE SET chapter_id = EXCLUDED.chapter_id, difficulty = EXCLUDED.difficulty, question = EXCLUDED.question, answer = EXCLUDED.answer, unit = EXCLUDED.unit, solution = EXCLUDED.solution, hints = EXCLUDED.hints;
INSERT INTO public.exercises (id, chapter_id, difficulty, question, answer, unit, solution, hints) VALUES ('long-ex-3', 'longueurs', 'facile', 'Quelle est la longueur d''un segment de 45 mm en cm ?', '4,5', 'cm', '1 cm = 10 mm, donc 45 mm = 45 ÷ 10 = 4,5 cm.', '{"Divise par 10."}') ON CONFLICT (id) DO UPDATE SET chapter_id = EXCLUDED.chapter_id, difficulty = EXCLUDED.difficulty, question = EXCLUDED.question, answer = EXCLUDED.answer, unit = EXCLUDED.unit, solution = EXCLUDED.solution, hints = EXCLUDED.hints;
INSERT INTO public.exercises (id, chapter_id, difficulty, question, answer, unit, solution, hints) VALUES ('long-ex-4', 'longueurs', 'moyen', 'Calcule le périmètre d''un carré de côté 7 cm.', '28', 'cm', 'Périmètre = 4 × côté = 4 × 7 = 28 cm.', '{"Un carré a 4 côtés égaux."}') ON CONFLICT (id) DO UPDATE SET chapter_id = EXCLUDED.chapter_id, difficulty = EXCLUDED.difficulty, question = EXCLUDED.question, answer = EXCLUDED.answer, unit = EXCLUDED.unit, solution = EXCLUDED.solution, hints = EXCLUDED.hints;
INSERT INTO public.exercises (id, chapter_id, difficulty, question, answer, unit, solution, hints) VALUES ('long-ex-5', 'longueurs', 'moyen', 'Calcule le périmètre d''un rectangle de longueur 9 cm et largeur 5 cm.', '28', 'cm', 'Périmètre = 2 × (L + l) = 2 × (9 + 5) = 2 × 14 = 28 cm.', '{"Périmètre = somme de tous les côtés."}') ON CONFLICT (id) DO UPDATE SET chapter_id = EXCLUDED.chapter_id, difficulty = EXCLUDED.difficulty, question = EXCLUDED.question, answer = EXCLUDED.answer, unit = EXCLUDED.unit, solution = EXCLUDED.solution, hints = EXCLUDED.hints;
INSERT INTO public.exercises (id, chapter_id, difficulty, question, answer, unit, solution, hints) VALUES ('long-ex-6', 'longueurs', 'moyen', 'Convertis 5,6 km en m.', '5600', 'm', '5,6 km = 5,6 × 1000 = 5600 m.', '{"Multiplie par 1000."}') ON CONFLICT (id) DO UPDATE SET chapter_id = EXCLUDED.chapter_id, difficulty = EXCLUDED.difficulty, question = EXCLUDED.question, answer = EXCLUDED.answer, unit = EXCLUDED.unit, solution = EXCLUDED.solution, hints = EXCLUDED.hints;
INSERT INTO public.exercises (id, chapter_id, difficulty, question, answer, unit, solution, hints) VALUES ('long-ex-7', 'longueurs', 'moyen', 'Quelle est la distance en mètres d''un chemin de 2,5 km ?', '2500', 'm', '2,5 km = 2,5 × 1000 = 2500 m.', '{"1 km = 1000 m."}') ON CONFLICT (id) DO UPDATE SET chapter_id = EXCLUDED.chapter_id, difficulty = EXCLUDED.difficulty, question = EXCLUDED.question, answer = EXCLUDED.answer, unit = EXCLUDED.unit, solution = EXCLUDED.solution, hints = EXCLUDED.hints;
INSERT INTO public.exercises (id, chapter_id, difficulty, question, answer, unit, solution, hints) VALUES ('long-ex-8', 'longueurs', 'difficile', 'Un polygone a 6 côtés égaux de 4 cm chacun. Quel est son périmètre ?', '24', 'cm', 'Périmètre = 6 × 4 = 24 cm.', '{"Multiplie le nombre de côtés par la longueur."}') ON CONFLICT (id) DO UPDATE SET chapter_id = EXCLUDED.chapter_id, difficulty = EXCLUDED.difficulty, question = EXCLUDED.question, answer = EXCLUDED.answer, unit = EXCLUDED.unit, solution = EXCLUDED.solution, hints = EXCLUDED.hints;
INSERT INTO public.exercises (id, chapter_id, difficulty, question, answer, unit, solution, hints) VALUES ('long-ex-9', 'longueurs', 'difficile', 'Convertis 350 cm en mètres.', '3,5', 'm', '350 cm = 350 ÷ 100 = 3,5 m.', '{"Divise par 100."}') ON CONFLICT (id) DO UPDATE SET chapter_id = EXCLUDED.chapter_id, difficulty = EXCLUDED.difficulty, question = EXCLUDED.question, answer = EXCLUDED.answer, unit = EXCLUDED.unit, solution = EXCLUDED.solution, hints = EXCLUDED.hints;
INSERT INTO public.exercises (id, chapter_id, difficulty, question, answer, unit, solution, hints) VALUES ('long-ex-10', 'longueurs', 'difficile', 'La circonférence d''un cercle de rayon 5 cm est d''environ combien ? (π ≈ 3,14)', '31,4', 'cm', 'Circonférence = 2 × π × r = 2 × 3,14 × 5 = 31,4 cm.', '{"Utilise la formule 2πr."}') ON CONFLICT (id) DO UPDATE SET chapter_id = EXCLUDED.chapter_id, difficulty = EXCLUDED.difficulty, question = EXCLUDED.question, answer = EXCLUDED.answer, unit = EXCLUDED.unit, solution = EXCLUDED.solution, hints = EXCLUDED.hints;
INSERT INTO public.exercises (id, chapter_id, difficulty, question, answer, unit, solution, hints) VALUES ('aire-ex-1', 'aires', 'facile', 'Calcule l''aire d''un rectangle de longueur 8 cm et de largeur 5 cm.', '40', 'cm²', 'Aire = Longueur × Largeur = 8 × 5 = 40 cm².', '{"Utilise la formule A = L × l."}') ON CONFLICT (id) DO UPDATE SET chapter_id = EXCLUDED.chapter_id, difficulty = EXCLUDED.difficulty, question = EXCLUDED.question, answer = EXCLUDED.answer, unit = EXCLUDED.unit, solution = EXCLUDED.solution, hints = EXCLUDED.hints;
INSERT INTO public.exercises (id, chapter_id, difficulty, question, answer, unit, solution, hints) VALUES ('aire-ex-2', 'aires', 'facile', 'Quelle est l''aire d''un carré de côté 6 cm ?', '36', 'cm²', 'Aire = côté² = 6 × 6 = 36 cm².', '{"Multiplie le côté par lui-même."}') ON CONFLICT (id) DO UPDATE SET chapter_id = EXCLUDED.chapter_id, difficulty = EXCLUDED.difficulty, question = EXCLUDED.question, answer = EXCLUDED.answer, unit = EXCLUDED.unit, solution = EXCLUDED.solution, hints = EXCLUDED.hints;
INSERT INTO public.exercises (id, chapter_id, difficulty, question, answer, unit, solution, hints) VALUES ('aire-ex-3', 'aires', 'facile', 'Calcule l''aire d''un rectangle de 10 m sur 4 m.', '40', 'm²', 'Aire = 10 × 4 = 40 m².', '{"Longueur × largeur."}') ON CONFLICT (id) DO UPDATE SET chapter_id = EXCLUDED.chapter_id, difficulty = EXCLUDED.difficulty, question = EXCLUDED.question, answer = EXCLUDED.answer, unit = EXCLUDED.unit, solution = EXCLUDED.solution, hints = EXCLUDED.hints;
INSERT INTO public.exercises (id, chapter_id, difficulty, question, answer, unit, solution, hints) VALUES ('aire-ex-4', 'aires', 'moyen', 'Un terrain rectangulaire fait 25 m de long et 12 m de large. Quelle est son aire ?', '300', 'm²', 'Aire = 25 × 12 = 300 m².', '{"Multiplie longueur par largeur."}') ON CONFLICT (id) DO UPDATE SET chapter_id = EXCLUDED.chapter_id, difficulty = EXCLUDED.difficulty, question = EXCLUDED.question, answer = EXCLUDED.answer, unit = EXCLUDED.unit, solution = EXCLUDED.solution, hints = EXCLUDED.hints;
INSERT INTO public.exercises (id, chapter_id, difficulty, question, answer, unit, solution, hints) VALUES ('aire-ex-5', 'aires', 'moyen', 'Quelle est l''aire d''un triangle de base 10 cm et hauteur 6 cm ?', '30', 'cm²', 'Aire = (base × hauteur) ÷ 2 = (10 × 6) ÷ 2 = 30 cm².', '{"Formule du triangle : (b × h) / 2."}') ON CONFLICT (id) DO UPDATE SET chapter_id = EXCLUDED.chapter_id, difficulty = EXCLUDED.difficulty, question = EXCLUDED.question, answer = EXCLUDED.answer, unit = EXCLUDED.unit, solution = EXCLUDED.solution, hints = EXCLUDED.hints;
INSERT INTO public.exercises (id, chapter_id, difficulty, question, answer, unit, solution, hints) VALUES ('aire-ex-6', 'aires', 'moyen', 'Un carré a un périmètre de 20 cm. Quelle est son aire ?', '25', 'cm²', 'Côté = 20 ÷ 4 = 5 cm. Aire = 5² = 25 cm².', '{"Trouve d''abord le côté."}') ON CONFLICT (id) DO UPDATE SET chapter_id = EXCLUDED.chapter_id, difficulty = EXCLUDED.difficulty, question = EXCLUDED.question, answer = EXCLUDED.answer, unit = EXCLUDED.unit, solution = EXCLUDED.solution, hints = EXCLUDED.hints;
INSERT INTO public.exercises (id, chapter_id, difficulty, question, answer, unit, solution, hints) VALUES ('aire-ex-7', 'aires', 'moyen', 'Calcule l''aire d''un rectangle de 7,5 m sur 4 m.', '30', 'm²', 'Aire = 7,5 × 4 = 30 m².', '{"Multiplie les dimensions."}') ON CONFLICT (id) DO UPDATE SET chapter_id = EXCLUDED.chapter_id, difficulty = EXCLUDED.difficulty, question = EXCLUDED.question, answer = EXCLUDED.answer, unit = EXCLUDED.unit, solution = EXCLUDED.solution, hints = EXCLUDED.hints;
INSERT INTO public.exercises (id, chapter_id, difficulty, question, answer, unit, solution, hints) VALUES ('aire-ex-8', 'aires', 'difficile', 'L''aire d''un rectangle est 48 cm². Sa longueur est 8 cm. Quelle est sa largeur ?', '6', 'cm', 'Largeur = Aire ÷ Longueur = 48 ÷ 8 = 6 cm.', '{"Aire = L × l, donc l = Aire ÷ L."}') ON CONFLICT (id) DO UPDATE SET chapter_id = EXCLUDED.chapter_id, difficulty = EXCLUDED.difficulty, question = EXCLUDED.question, answer = EXCLUDED.answer, unit = EXCLUDED.unit, solution = EXCLUDED.solution, hints = EXCLUDED.hints;
INSERT INTO public.exercises (id, chapter_id, difficulty, question, answer, unit, solution, hints) VALUES ('aire-ex-9', 'aires', 'difficile', 'Quelle est l''aire d''un disque de rayon 4 cm ? (π ≈ 3,14)', '50,24', 'cm²', 'Aire = π × r² = 3,14 × 4² = 3,14 × 16 = 50,24 cm².', '{"Formule : πr²."}') ON CONFLICT (id) DO UPDATE SET chapter_id = EXCLUDED.chapter_id, difficulty = EXCLUDED.difficulty, question = EXCLUDED.question, answer = EXCLUDED.answer, unit = EXCLUDED.unit, solution = EXCLUDED.solution, hints = EXCLUDED.hints;
INSERT INTO public.exercises (id, chapter_id, difficulty, question, answer, unit, solution, hints) VALUES ('aire-ex-10', 'aires', 'difficile', 'Un triangle a une base de 12 cm et une aire de 54 cm². Quelle est sa hauteur ?', '9', 'cm', 'Aire = (b × h) ÷ 2, donc h = (Aire × 2) ÷ b = (54 × 2) ÷ 12 = 9 cm.', '{"Réarrange la formule du triangle."}') ON CONFLICT (id) DO UPDATE SET chapter_id = EXCLUDED.chapter_id, difficulty = EXCLUDED.difficulty, question = EXCLUDED.question, answer = EXCLUDED.answer, unit = EXCLUDED.unit, solution = EXCLUDED.solution, hints = EXCLUDED.hints;
INSERT INTO public.exercises (id, chapter_id, difficulty, question, answer, unit, solution, hints) VALUES ('vol-ex-1', 'volumes', 'facile', 'Quel est le volume d''un cube de côté 3 cm ?', '27', 'cm³', 'Volume = côté³ = 3 × 3 × 3 = 27 cm³.', '{"Multiplie le côté 3 fois."}') ON CONFLICT (id) DO UPDATE SET chapter_id = EXCLUDED.chapter_id, difficulty = EXCLUDED.difficulty, question = EXCLUDED.question, answer = EXCLUDED.answer, unit = EXCLUDED.unit, solution = EXCLUDED.solution, hints = EXCLUDED.hints;
INSERT INTO public.exercises (id, chapter_id, difficulty, question, answer, unit, solution, hints) VALUES ('vol-ex-2', 'volumes', 'facile', 'Calcule le volume d''un pavé de dimensions 4 cm, 3 cm, 2 cm.', '24', 'cm³', 'Volume = L × l × h = 4 × 3 × 2 = 24 cm³.', '{"Multiplie les trois dimensions."}') ON CONFLICT (id) DO UPDATE SET chapter_id = EXCLUDED.chapter_id, difficulty = EXCLUDED.difficulty, question = EXCLUDED.question, answer = EXCLUDED.answer, unit = EXCLUDED.unit, solution = EXCLUDED.solution, hints = EXCLUDED.hints;
INSERT INTO public.exercises (id, chapter_id, difficulty, question, answer, unit, solution, hints) VALUES ('vol-ex-3', 'volumes', 'facile', 'Quel est le volume d''un cube de 5 cm de côté ?', '125', 'cm³', 'Volume = 5³ = 5 × 5 × 5 = 125 cm³.', '{"5 × 5 × 5."}') ON CONFLICT (id) DO UPDATE SET chapter_id = EXCLUDED.chapter_id, difficulty = EXCLUDED.difficulty, question = EXCLUDED.question, answer = EXCLUDED.answer, unit = EXCLUDED.unit, solution = EXCLUDED.solution, hints = EXCLUDED.hints;
INSERT INTO public.exercises (id, chapter_id, difficulty, question, answer, unit, solution, hints) VALUES ('vol-ex-4', 'volumes', 'moyen', 'Calcule le volume d''un pavé droit de 6 cm sur 4 cm sur 5 cm.', '120', 'cm³', 'Volume = 6 × 4 × 5 = 120 cm³.', '{"Longueur × largeur × hauteur."}') ON CONFLICT (id) DO UPDATE SET chapter_id = EXCLUDED.chapter_id, difficulty = EXCLUDED.difficulty, question = EXCLUDED.question, answer = EXCLUDED.answer, unit = EXCLUDED.unit, solution = EXCLUDED.solution, hints = EXCLUDED.hints;
INSERT INTO public.exercises (id, chapter_id, difficulty, question, answer, unit, solution, hints) VALUES ('vol-ex-5', 'volumes', 'moyen', 'Un aquarium cubique a un côté de 20 cm. Quel est son volume ?', '8000', 'cm³', 'Volume = 20³ = 20 × 20 × 20 = 8000 cm³.', '{"C''est un cube."}') ON CONFLICT (id) DO UPDATE SET chapter_id = EXCLUDED.chapter_id, difficulty = EXCLUDED.difficulty, question = EXCLUDED.question, answer = EXCLUDED.answer, unit = EXCLUDED.unit, solution = EXCLUDED.solution, hints = EXCLUDED.hints;
INSERT INTO public.exercises (id, chapter_id, difficulty, question, answer, unit, solution, hints) VALUES ('vol-ex-6', 'volumes', 'moyen', 'Convertis 2 litres en cm³.', '2000', 'cm³', '1 litre = 1000 cm³, donc 2 litres = 2000 cm³.', '{"1 L = 1000 cm³."}') ON CONFLICT (id) DO UPDATE SET chapter_id = EXCLUDED.chapter_id, difficulty = EXCLUDED.difficulty, question = EXCLUDED.question, answer = EXCLUDED.answer, unit = EXCLUDED.unit, solution = EXCLUDED.solution, hints = EXCLUDED.hints;
INSERT INTO public.exercises (id, chapter_id, difficulty, question, answer, unit, solution, hints) VALUES ('vol-ex-7', 'volumes', 'moyen', 'Quel est le volume en litres d''un pavé de 10 cm × 10 cm × 10 cm ?', '1', 'L', 'Volume = 10³ = 1000 cm³ = 1 litre.', '{"1000 cm³ = 1 L."}') ON CONFLICT (id) DO UPDATE SET chapter_id = EXCLUDED.chapter_id, difficulty = EXCLUDED.difficulty, question = EXCLUDED.question, answer = EXCLUDED.answer, unit = EXCLUDED.unit, solution = EXCLUDED.solution, hints = EXCLUDED.hints;
INSERT INTO public.exercises (id, chapter_id, difficulty, question, answer, unit, solution, hints) VALUES ('vol-ex-8', 'volumes', 'difficile', 'Un pavé a un volume de 60 cm³. Sa base fait 12 cm². Quelle est sa hauteur ?', '5', 'cm', 'Hauteur = Volume ÷ Aire base = 60 ÷ 12 = 5 cm.', '{"Volume = Aire base × hauteur."}') ON CONFLICT (id) DO UPDATE SET chapter_id = EXCLUDED.chapter_id, difficulty = EXCLUDED.difficulty, question = EXCLUDED.question, answer = EXCLUDED.answer, unit = EXCLUDED.unit, solution = EXCLUDED.solution, hints = EXCLUDED.hints;
