INSERT INTO public.exercises (id, chapter_id, difficulty, question, answer, unit, solution, hints) VALUES ('prop-ex-3', 'proportionnalite', 'facile', '3 gâteaux coûtent 9 €. Quel est le prix d''un gâteau ?', '3', '€', '9 ÷ 3 = 3 € le gâteau.', '{"Divise le prix total par 3."}') ON CONFLICT (id) DO UPDATE SET chapter_id = EXCLUDED.chapter_id, difficulty = EXCLUDED.difficulty, question = EXCLUDED.question, answer = EXCLUDED.answer, unit = EXCLUDED.unit, solution = EXCLUDED.solution, hints = EXCLUDED.hints;
INSERT INTO public.exercises (id, chapter_id, difficulty, question, answer, unit, solution, hints) VALUES ('prop-ex-4', 'proportionnalite', 'moyen', 'Si 2 kg de pommes coûtent 6 €, combien coûtent 5 kg ?', '15', '€', 'Prix pour 1 kg = 6 ÷ 2 = 3 €. Pour 5 kg : 5 × 3 = 15 €.', '{"Cherche d''abord le prix de 1 kg."}') ON CONFLICT (id) DO UPDATE SET chapter_id = EXCLUDED.chapter_id, difficulty = EXCLUDED.difficulty, question = EXCLUDED.question, answer = EXCLUDED.answer, unit = EXCLUDED.unit, solution = EXCLUDED.solution, hints = EXCLUDED.hints;
INSERT INTO public.exercises (id, chapter_id, difficulty, question, answer, unit, solution, hints) VALUES ('prop-ex-5', 'proportionnalite', 'moyen', 'Pour faire 4 crêpes, il faut 200 g de farine. Combien pour 10 crêpes ?', '500', 'g', '200 ÷ 4 = 50 g par crêpe. 50 × 10 = 500 g.', '{"Calcule pour 1 crêpe d''abord."}') ON CONFLICT (id) DO UPDATE SET chapter_id = EXCLUDED.chapter_id, difficulty = EXCLUDED.difficulty, question = EXCLUDED.question, answer = EXCLUDED.answer, unit = EXCLUDED.unit, solution = EXCLUDED.solution, hints = EXCLUDED.hints;
INSERT INTO public.exercises (id, chapter_id, difficulty, question, answer, unit, solution, hints) VALUES ('prop-ex-6', 'proportionnalite', 'moyen', 'Calcule 25% de 80.', '20', '', '25% = 25/100 = 1/4. 80 ÷ 4 = 20.', '{"25% = 1/4."}') ON CONFLICT (id) DO UPDATE SET chapter_id = EXCLUDED.chapter_id, difficulty = EXCLUDED.difficulty, question = EXCLUDED.question, answer = EXCLUDED.answer, unit = EXCLUDED.unit, solution = EXCLUDED.solution, hints = EXCLUDED.hints;
INSERT INTO public.exercises (id, chapter_id, difficulty, question, answer, unit, solution, hints) VALUES ('prop-ex-7', 'proportionnalite', 'moyen', 'Un article coûte 50 € avec 10% de réduction. Quel est le prix final ?', '45', '€', '10% de 50 = 5 €. Prix final = 50 - 5 = 45 €.', '{"Calcule 10% puis soustrais."}') ON CONFLICT (id) DO UPDATE SET chapter_id = EXCLUDED.chapter_id, difficulty = EXCLUDED.difficulty, question = EXCLUDED.question, answer = EXCLUDED.answer, unit = EXCLUDED.unit, solution = EXCLUDED.solution, hints = EXCLUDED.hints;
INSERT INTO public.exercises (id, chapter_id, difficulty, question, answer, unit, solution, hints) VALUES ('prop-ex-8', 'proportionnalite', 'difficile', 'Une voiture roule à 60 km/h. Quelle distance parcourt-elle en 2h30 ?', '150', 'km', '2h30 = 2,5 h. Distance = 60 × 2,5 = 150 km.', '{"Convertis 2h30 en heures décimales."}') ON CONFLICT (id) DO UPDATE SET chapter_id = EXCLUDED.chapter_id, difficulty = EXCLUDED.difficulty, question = EXCLUDED.question, answer = EXCLUDED.answer, unit = EXCLUDED.unit, solution = EXCLUDED.solution, hints = EXCLUDED.hints;
INSERT INTO public.exercises (id, chapter_id, difficulty, question, answer, unit, solution, hints) VALUES ('prop-ex-9', 'proportionnalite', 'difficile', 'Sur une carte à l''échelle 1:100000, 5 cm représentent quelle distance réelle ?', '5', 'km', '5 cm × 100000 = 500000 cm = 5000 m = 5 km.', '{"Multiplie par l''échelle puis convertis."}') ON CONFLICT (id) DO UPDATE SET chapter_id = EXCLUDED.chapter_id, difficulty = EXCLUDED.difficulty, question = EXCLUDED.question, answer = EXCLUDED.answer, unit = EXCLUDED.unit, solution = EXCLUDED.solution, hints = EXCLUDED.hints;
INSERT INTO public.exercises (id, chapter_id, difficulty, question, answer, unit, solution, hints) VALUES ('prop-ex-10', 'proportionnalite', 'difficile', 'Calcule 15% de 240.', '36', '', '15% = 15/100. 240 × 15/100 = 240 × 0,15 = 36.', '{"Multiplie par 0,15."}') ON CONFLICT (id) DO UPDATE SET chapter_id = EXCLUDED.chapter_id, difficulty = EXCLUDED.difficulty, question = EXCLUDED.question, answer = EXCLUDED.answer, unit = EXCLUDED.unit, solution = EXCLUDED.solution, hints = EXCLUDED.hints;
INSERT INTO public.exercises (id, chapter_id, difficulty, question, answer, unit, solution, hints) VALUES ('info-ex-1', 'pensee-informatique', 'facile', 'Un robot avance de 5 pas, tourne, puis avance de 5 pas. S''il répète cela 4 fois, combien de pas fait-il ?', '40', 'pas', 'Chaque série fait 5 + 5 = 10 pas. Répété 4 fois : 10 × 4 = 40 pas.', '{"Calcule le nombre de pas dans une boucle."}') ON CONFLICT (id) DO UPDATE SET chapter_id = EXCLUDED.chapter_id, difficulty = EXCLUDED.difficulty, question = EXCLUDED.question, answer = EXCLUDED.answer, unit = EXCLUDED.unit, solution = EXCLUDED.solution, hints = EXCLUDED.hints;
INSERT INTO public.exercises (id, chapter_id, difficulty, question, answer, unit, solution, hints) VALUES ('info-ex-2', 'pensee-informatique', 'facile', 'Combien de fois la boucle s''exécute-t-elle : pour i de 1 à 5 ?', '5', 'fois', 'La boucle s''exécute 5 fois (i = 1, 2, 3, 4, 5).', '{"Compte de 1 à 5."}') ON CONFLICT (id) DO UPDATE SET chapter_id = EXCLUDED.chapter_id, difficulty = EXCLUDED.difficulty, question = EXCLUDED.question, answer = EXCLUDED.answer, unit = EXCLUDED.unit, solution = EXCLUDED.solution, hints = EXCLUDED.hints;
INSERT INTO public.exercises (id, chapter_id, difficulty, question, answer, unit, solution, hints) VALUES ('info-ex-3', 'pensee-informatique', 'facile', 'Si un algorithme dit ''répète 3 fois : ajoute 2'', en partant de 0, quel est le résultat ?', '6', '', '0 + 2 + 2 + 2 = 6.', '{"Ajoute 2 trois fois."}') ON CONFLICT (id) DO UPDATE SET chapter_id = EXCLUDED.chapter_id, difficulty = EXCLUDED.difficulty, question = EXCLUDED.question, answer = EXCLUDED.answer, unit = EXCLUDED.unit, solution = EXCLUDED.solution, hints = EXCLUDED.hints;
INSERT INTO public.exercises (id, chapter_id, difficulty, question, answer, unit, solution, hints) VALUES ('info-ex-4', 'pensee-informatique', 'moyen', 'Un robot tourne de 90° à droite 4 fois. De combien a-t-il tourné au total ?', '360', '°', '90 × 4 = 360° (un tour complet).', '{"Multiplie 90 par 4."}') ON CONFLICT (id) DO UPDATE SET chapter_id = EXCLUDED.chapter_id, difficulty = EXCLUDED.difficulty, question = EXCLUDED.question, answer = EXCLUDED.answer, unit = EXCLUDED.unit, solution = EXCLUDED.solution, hints = EXCLUDED.hints;
INSERT INTO public.exercises (id, chapter_id, difficulty, question, answer, unit, solution, hints) VALUES ('info-ex-5', 'pensee-informatique', 'moyen', 'Si un programme double un nombre 3 fois en partant de 2, quel est le résultat ?', '16', '', '2 × 2 = 4, 4 × 2 = 8, 8 × 2 = 16.', '{"Double à chaque étape."}') ON CONFLICT (id) DO UPDATE SET chapter_id = EXCLUDED.chapter_id, difficulty = EXCLUDED.difficulty, question = EXCLUDED.question, answer = EXCLUDED.answer, unit = EXCLUDED.unit, solution = EXCLUDED.solution, hints = EXCLUDED.hints;
INSERT INTO public.exercises (id, chapter_id, difficulty, question, answer, unit, solution, hints) VALUES ('info-ex-6', 'pensee-informatique', 'moyen', 'Combien de pas fait un carré de côté 10 si le robot trace tous les côtés ?', '40', 'pas', '4 côtés × 10 pas = 40 pas.', '{"4 côtés dans un carré."}') ON CONFLICT (id) DO UPDATE SET chapter_id = EXCLUDED.chapter_id, difficulty = EXCLUDED.difficulty, question = EXCLUDED.question, answer = EXCLUDED.answer, unit = EXCLUDED.unit, solution = EXCLUDED.solution, hints = EXCLUDED.hints;
INSERT INTO public.exercises (id, chapter_id, difficulty, question, answer, unit, solution, hints) VALUES ('info-ex-7', 'pensee-informatique', 'moyen', 'Un algorithme compte de 2 en 2 : 2, 4, 6, ... Quel est le 5ème nombre ?', '10', '', '2, 4, 6, 8, 10. Le 5ème est 10.', '{"Continue la suite."}') ON CONFLICT (id) DO UPDATE SET chapter_id = EXCLUDED.chapter_id, difficulty = EXCLUDED.difficulty, question = EXCLUDED.question, answer = EXCLUDED.answer, unit = EXCLUDED.unit, solution = EXCLUDED.solution, hints = EXCLUDED.hints;
INSERT INTO public.exercises (id, chapter_id, difficulty, question, answer, unit, solution, hints) VALUES ('info-ex-8', 'pensee-informatique', 'difficile', 'Pour tracer un triangle équilatéral, le robot doit tourner de combien à chaque sommet ?', '120', '°', '360° ÷ 3 = 120° par sommet.', '{"Divise 360 par le nombre de côtés."}') ON CONFLICT (id) DO UPDATE SET chapter_id = EXCLUDED.chapter_id, difficulty = EXCLUDED.difficulty, question = EXCLUDED.question, answer = EXCLUDED.answer, unit = EXCLUDED.unit, solution = EXCLUDED.solution, hints = EXCLUDED.hints;
INSERT INTO public.exercises (id, chapter_id, difficulty, question, answer, unit, solution, hints) VALUES ('info-ex-9', 'pensee-informatique', 'difficile', 'Un algorithme calcule n × 2 + 3. Si n = 7, quel est le résultat ?', '17', '', '7 × 2 + 3 = 14 + 3 = 17.', '{"Multiplie d''abord, puis ajoute."}') ON CONFLICT (id) DO UPDATE SET chapter_id = EXCLUDED.chapter_id, difficulty = EXCLUDED.difficulty, question = EXCLUDED.question, answer = EXCLUDED.answer, unit = EXCLUDED.unit, solution = EXCLUDED.solution, hints = EXCLUDED.hints;
INSERT INTO public.exercises (id, chapter_id, difficulty, question, answer, unit, solution, hints) VALUES ('info-ex-10', 'pensee-informatique', 'difficile', 'Pour tracer un hexagone régulier, le robot tourne de combien à chaque sommet ?', '60', '°', '360° ÷ 6 = 60°.', '{"360 divisé par le nombre de côtés."}') ON CONFLICT (id) DO UPDATE SET chapter_id = EXCLUDED.chapter_id, difficulty = EXCLUDED.difficulty, question = EXCLUDED.question, answer = EXCLUDED.answer, unit = EXCLUDED.unit, solution = EXCLUDED.solution, hints = EXCLUDED.hints;
INSERT INTO public.formulas (id, chapter_id, title, formula, description, tags, examples) VALUES ('dec-1', 'nombres-entiers-decimaux', 'Décomposition décimale', '12,345 = 12 + 3/10 + 4/100 + 5/1000', 'Chaque chiffre après la virgule indique des dixièmes, centièmes, millièmes… La valeur de position permet de lire, comparer et arrondir.', '{"Décimaux","Numération"}', '[{"context":"0,75","calculation":"7 est le chiffre des dixièmes, 5 des centièmes."},{"context":"Arrondir 3,486 au centième","calculation":"3,49 car le chiffre suivant (6) est ≥ 5."}]') ON CONFLICT (id) DO UPDATE SET chapter_id = EXCLUDED.chapter_id, title = EXCLUDED.title, formula = EXCLUDED.formula, description = EXCLUDED.description, tags = EXCLUDED.tags, examples = EXCLUDED.examples;
INSERT INTO public.formulas (id, chapter_id, title, formula, description, tags, examples) VALUES ('frac-1', 'fractions', 'Fraction quotient', 'a/b = a ÷ b', 'La fraction représente le quotient de a par b : (a/b) × b = a. Elle peut se placer sur une droite graduée et se simplifier.', '{"Fractions","Division"}', '[{"context":"4 × (3/4)","calculation":"4 × 3/4 = 3"},{"context":"Simplifier 6/12","calculation":"6/12 = (6÷6)/(12÷6) = 1/2"}]') ON CONFLICT (id) DO UPDATE SET chapter_id = EXCLUDED.chapter_id, title = EXCLUDED.title, formula = EXCLUDED.formula, description = EXCLUDED.description, tags = EXCLUDED.tags, examples = EXCLUDED.examples;
INSERT INTO public.formulas (id, chapter_id, title, formula, description, tags, examples) VALUES ('frac-2', 'fractions', 'Part d''une quantité', 'Part = (k / n) × Q', 'Pour prendre k parts sur n d''une quantité Q, on multiplie Q par la fraction k/n.', '{"Fractions","Proportion"}', '[{"context":"3/4 de 20 €","calculation":"20 × 3/4 = 15 €"},{"context":"2/3 de 12","calculation":"12 × 2/3 = 8"}]') ON CONFLICT (id) DO UPDATE SET chapter_id = EXCLUDED.chapter_id, title = EXCLUDED.title, formula = EXCLUDED.formula, description = EXCLUDED.description, tags = EXCLUDED.tags, examples = EXCLUDED.examples;
INSERT INTO public.formulas (id, chapter_id, title, formula, description, tags, examples) VALUES ('aire-rect', 'aires', 'Aire du rectangle', 'A = L × l', 'Surface obtenue en multipliant longueur par largeur. Attention aux unités (cm × cm = cm²).', '{"Géométrie","Aire"}', '[{"context":"8 cm × 5 cm","calculation":"A = 8 × 5 = 40 cm²"}]') ON CONFLICT (id) DO UPDATE SET chapter_id = EXCLUDED.chapter_id, title = EXCLUDED.title, formula = EXCLUDED.formula, description = EXCLUDED.description, tags = EXCLUDED.tags, examples = EXCLUDED.examples;
INSERT INTO public.formulas (id, chapter_id, title, formula, description, tags, examples) VALUES ('aire-tri', 'aires', 'Aire du triangle', 'A = (b × h) / 2', 'On prend la moitié du produit base × hauteur (hauteur perpendiculaire à la base).', '{"Géométrie","Aire"}', '[{"context":"b = 10 cm, h = 6 cm","calculation":"A = (10 × 6) / 2 = 30 cm²"}]') ON CONFLICT (id) DO UPDATE SET chapter_id = EXCLUDED.chapter_id, title = EXCLUDED.title, formula = EXCLUDED.formula, description = EXCLUDED.description, tags = EXCLUDED.tags, examples = EXCLUDED.examples;
INSERT INTO public.formulas (id, chapter_id, title, formula, description, tags, examples) VALUES ('aire-disque', 'aires', 'Aire du disque', 'A = π × r²', 'La surface d''un disque dépend du carré du rayon. Utiliser π ≈ 3,14.', '{"Cercle","Aire"}', '[{"context":"r = 4 cm","calculation":"A ≈ 3,14 × 4² = 50,24 cm²"}]') ON CONFLICT (id) DO UPDATE SET chapter_id = EXCLUDED.chapter_id, title = EXCLUDED.title, formula = EXCLUDED.formula, description = EXCLUDED.description, tags = EXCLUDED.tags, examples = EXCLUDED.examples;
INSERT INTO public.formulas (id, chapter_id, title, formula, description, tags, examples) VALUES ('perim-cercle', 'longueurs', 'Circonférence du cercle', 'C = 2 × π × r = π × D', 'Le périmètre du cercle se calcule avec le rayon r ou le diamètre D.', '{"Cercle","Longueur"}', '[{"context":"r = 5 cm","calculation":"C ≈ 2 × 3,14 × 5 = 31,4 cm"}]') ON CONFLICT (id) DO UPDATE SET chapter_id = EXCLUDED.chapter_id, title = EXCLUDED.title, formula = EXCLUDED.formula, description = EXCLUDED.description, tags = EXCLUDED.tags, examples = EXCLUDED.examples;
INSERT INTO public.formulas (id, chapter_id, title, formula, description, tags, examples) VALUES ('perim-rect', 'longueurs', 'Périmètre du rectangle', 'P = 2 × (L + l)', 'Somme des longueurs des 4 côtés d''un rectangle (deux longueurs, deux largeurs).', '{"Longueur","Périmètre"}', '[{"context":"L = 9 cm, l = 5 cm","calculation":"P = 2 × (9 + 5) = 28 cm"}]') ON CONFLICT (id) DO UPDATE SET chapter_id = EXCLUDED.chapter_id, title = EXCLUDED.title, formula = EXCLUDED.formula, description = EXCLUDED.description, tags = EXCLUDED.tags, examples = EXCLUDED.examples;
INSERT INTO public.formulas (id, chapter_id, title, formula, description, tags, examples) VALUES ('vol-cube', 'volumes', 'Volume du cube', 'V = c³', 'On multiplie l''arête c trois fois. L''unité devient un cube (cm³, m³).', '{"Volume","Solide"}', '[{"context":"c = 3 cm","calculation":"V = 3 × 3 × 3 = 27 cm³"}]') ON CONFLICT (id) DO UPDATE SET chapter_id = EXCLUDED.chapter_id, title = EXCLUDED.title, formula = EXCLUDED.formula, description = EXCLUDED.description, tags = EXCLUDED.tags, examples = EXCLUDED.examples;
INSERT INTO public.formulas (id, chapter_id, title, formula, description, tags, examples) VALUES ('vol-pave', 'volumes', 'Volume du pavé droit', 'V = L × l × h', 'Produit des trois dimensions : longueur, largeur, hauteur.', '{"Volume","Solide"}', '[{"context":"6 cm × 4 cm × 5 cm","calculation":"V = 6 × 4 × 5 = 120 cm³"}]') ON CONFLICT (id) DO UPDATE SET chapter_id = EXCLUDED.chapter_id, title = EXCLUDED.title, formula = EXCLUDED.formula, description = EXCLUDED.description, tags = EXCLUDED.tags, examples = EXCLUDED.examples;
INSERT INTO public.formulas (id, chapter_id, title, formula, description, tags, examples) VALUES ('vol-litre', 'volumes', 'Équivalence litre - cm³', '1 L = 1000 cm³', 'Relation clé entre volume (cm³) et capacité (litre).', '{"Volume","Conversion"}', '[{"context":"2 L en cm³","calculation":"2 × 1000 = 2000 cm³"}]') ON CONFLICT (id) DO UPDATE SET chapter_id = EXCLUDED.chapter_id, title = EXCLUDED.title, formula = EXCLUDED.formula, description = EXCLUDED.description, tags = EXCLUDED.tags, examples = EXCLUDED.examples;
INSERT INTO public.formulas (id, chapter_id, title, formula, description, tags, examples) VALUES ('prop-1', 'proportionnalite', 'Règle de trois', 'x = (b × c) ÷ a', 'Dans un tableau proportionnel (a ↔ b), (c ↔ x), on calcule la quatrième proportionnelle en multipliant en croix puis en divisant.', '{"Proportionnalité","Pourcentage"}', '[{"context":"2 kg → 6 € ; 5 kg → ?","calculation":"x = (6 × 5) ÷ 2 = 15 €"}]') ON CONFLICT (id) DO UPDATE SET chapter_id = EXCLUDED.chapter_id, title = EXCLUDED.title, formula = EXCLUDED.formula, description = EXCLUDED.description, tags = EXCLUDED.tags, examples = EXCLUDED.examples;
INSERT INTO public.formulas (id, chapter_id, title, formula, description, tags, examples) VALUES ('prop-2', 'proportionnalite', 'Pourcentage', 'Part = Total × (p / 100)', 'Un pourcentage p% d''un total se calcule en multipliant par p puis en divisant par 100.', '{"Pourcentage","Proportionnalité"}', '[{"context":"25% de 80","calculation":"80 × 25 / 100 = 20"}]') ON CONFLICT (id) DO UPDATE SET chapter_id = EXCLUDED.chapter_id, title = EXCLUDED.title, formula = EXCLUDED.formula, description = EXCLUDED.description, tags = EXCLUDED.tags, examples = EXCLUDED.examples;
INSERT INTO public.formulas (id, chapter_id, title, formula, description, tags, examples) VALUES ('temps-1', 'temps-durees', 'Conversions de durées', '1 h = 60 min ; 1 min = 60 s', 'Pour passer des heures aux minutes ou secondes, on multiplie ; pour revenir, on divise.', '{"Temps","Conversion"}', '[{"context":"2 h 30 min en minutes","calculation":"2 × 60 + 30 = 150 min"}]') ON CONFLICT (id) DO UPDATE SET chapter_id = EXCLUDED.chapter_id, title = EXCLUDED.title, formula = EXCLUDED.formula, description = EXCLUDED.description, tags = EXCLUDED.tags, examples = EXCLUDED.examples;
INSERT INTO public.formulas (id, chapter_id, title, formula, description, tags, examples) VALUES ('algo-1', 'pensee-informatique', 'Boucle ''répéter n fois''', 'Répéter n fois : bloc d''instructions', 'Une boucle exécute le même bloc plusieurs fois. Utile pour tracer des figures régulières ou répéter une action.', '{"Algorithme","Répétition"}', '[{"context":"Tracer un carré de côté 10","calculation":"Répéter 4 fois : avancer 10 ; tourner 90°"}]') ON CONFLICT (id) DO UPDATE SET chapter_id = EXCLUDED.chapter_id, title = EXCLUDED.title, formula = EXCLUDED.formula, description = EXCLUDED.description, tags = EXCLUDED.tags, examples = EXCLUDED.examples;
